{"content": "#!/usr/bin/env node
// migrate-data.js — Reads all JSONs from the Nexa repo and inserts into Supabase/Postgres
// Usage: node scripts/migration/migrate-data.js

const fs = require('fs');
const path = require('path');
const { Client } = require('pg');

const REPO = path.resolve(__dirname, '../..');

const CONFIG = {
  host: process.env.PGHOST || 'localhost',
  port: parseInt(process.env.PGPORT || '5432'),
  user: process.env.PGUSER || 'postgres',
  password: [REDACTED] || '',
  database: 'nexa',
};

async function main() {
  const slug = 'nexa-paraguay';
  const locale = 'nl';

  console.log(`📦 Migrating tenant: ${slug}`);

  // 1. Load content JSON
  const contentPath = path.join(REPO, 'content', `${locale}.json`);
  const content = JSON.parse(fs.readFileSync(contentPath, 'utf-8'));
  console.log(`   content: ${(fs.statSync(contentPath).size / 1024).toFixed(0)}KB`);

  // 2. Load page configs (nexa-pages)
  const pagesDir = path.join(REPO, 'nexa-pages');
  const pageConfig = {};
  for (const file of fs.readdirSync(pagesDir).filter(f => f.endsWith('.json'))) {
    const slug = file.replace('.json', '');
    pageConfig[slug] = JSON.parse(fs.readFileSync(path.join(pagesDir, file), 'utf-8'));
  }
  console.log(`   pages: ${Object.keys(pageConfig).length} slugs`);

  // 3. Load images manifest
  const imagesPath = path.join(REPO, 'images.json');
  const images = JSON.parse(fs.readFileSync(imagesPath, 'utf-8'));
  console.log(`   images: ${images.totalImages || 'N/A'} entries`);

  // 4. Load site config
  const sitePath = path.join(REPO, 'site.json');
  const siteConfig = JSON.parse(fs.readFileSync(sitePath, 'utf-8'));
  console.log(`   site: ${siteConfig.vertical}`);

  // 5. Also load other locales as meta
  const locales = {};
  for (const loc of ['en', 'es', 'de']) {
    const locPath = path.join(REPO, 'content', `${loc}.json`);
    if (fs.existsSync(locPath)) {
      locales[loc] = JSON.parse(fs.readFileSync(locPath, 'utf-8'));
      console.log(`   locale ${loc}: ${(fs.statSync(locPath).size / 1024).toFixed(0)}KB`);
    }
  }

  // 6. Connect to DB and upsert
  const client = new Client(CONFIG);
  await client.connect();

  const result = await client.query(`
    INSERT INTO tenant_config (tenant_slug, domain, content, page_config, images, site_config, meta)
    VALUES ($1, $2, $3, $4, $5, $6, $7)
    ON CONFLICT (tenant_slug) 
    DO UPDATE SET 
      content = EXCLUDED.content,
      page_config = EXCLUDED.page_config,
      images = EXCLUDED.images,
      site_config = EXCLUDED.site_config,
