    28|
    29|// ── In-memory LRU Cache ──
    30|class LRUCache {
    31|  constructor(maxSize = 10, ttlMs = 30000) {
    32|    this.cache = new Map();
    33|    this.maxSize = maxSize;
    34|    this.ttlMs = ttlMs;
    35|  }
    36|
    37|  get(key) {
    38|    const entry = this.cache.get(key);
    39|    if (!entry) return null;
    40|    if (Date.now() - entry.timestamp > this.ttlMs) {
    41|      this.cache.delete(key);
    42|      return null;
    43|    }
    44|    // Move to end (most recently used)
    45|    this.cache.delete(key);
    46|    this.cache.set(key, entry);
    47|    return entry.value;
    48|  }
    49|
    50|  set(key, value) {
    51|    if (this.cache.size >= this.maxSize) {
    52|      // Delete oldest (first item)
    53|      const oldest = this.cache.keys().next().value;
    54|      this.cache.delete(oldest);
    55|    }
    56|    this.cache.set(key, { value, timestamp: Date.now() });
    57|  }
    58|
    59|  invalidate(key) {
    60|    this.cache.delete(key);
    61|  }
    62|
    63|  invalidateAll() {
    64|    this.cache.clear();
    65|  }
